import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"Agent 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/agent.md","filePath":"guide/architecture/agent.md"}'),p={name:"guide/architecture/agent.md"};function l(o,a,i,r,c,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="agent-模块" tabindex="-1">Agent 模块 <a class="header-anchor" href="#agent-模块" aria-label="Permalink to &quot;Agent 模块&quot;">​</a></h1><p><code>src/lab/agent/</code> — LLM 调用、工具循环、记忆管理。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent/</span></span>
<span class="line"><span>├── agent_factory.py          # AgentFactory：根据配置创建 Agent</span></span>
<span class="line"><span>├── stateless_llm_factory.py  # LLMFactory：创建 OpenAI Compatible LLM 实例</span></span>
<span class="line"><span>├── stateless_llm/</span></span>
<span class="line"><span>│   └── openai_compatible_llm.py  # AsyncLLM：异步流式 LLM 调用</span></span>
<span class="line"><span>├── input_types.py            # 输入类型（BatchInput / ImageData / TextData）</span></span>
<span class="line"><span>├── output_types.py           # 输出类型（SentenceOutput / AudioOutput / Actions）</span></span>
<span class="line"><span>├── transformers.py           # 文本后处理管线（断句、表情提取、TTS 过滤）</span></span>
<span class="line"><span>├── mcp_tool_loop.py          # MCP 工具循环执行器</span></span>
<span class="line"><span>└── agents/</span></span>
<span class="line"><span>    ├── agent_interface.py    # AgentInterface：抽象基类</span></span>
<span class="line"><span>    └── memory_agent/         # MemoryAgent：当前唯一实现</span></span>
<span class="line"><span>        ├── agent.py          # 编排器（orchestrator）</span></span>
<span class="line"><span>        ├── memory_store.py   # 内存消息列表 + 历史读写</span></span>
<span class="line"><span>        ├── message_factory.py # OpenAI Message 构造</span></span>
<span class="line"><span>        ├── prompt_builder.py  # System Prompt 拼装</span></span>
<span class="line"><span>        ├── tool_runner.py     # MCP 工具执行 + 回调图提取</span></span>
<span class="line"><span>        ├── vision_summarizer.py # 图片摘要生成</span></span>
<span class="line"><span>        └── types.py           # 内部类型</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="agentinterface" tabindex="-1">AgentInterface <a class="header-anchor" href="#agentinterface" aria-label="Permalink to &quot;AgentInterface&quot;">​</a></h3><p>所有 Agent 的抽象接口，定义三个核心方法：</p><ul><li><code>chat(input_data) → AsyncIterator[BaseOutput]</code> — 异步流式对话</li><li><code>handle_interrupt(heard_response)</code> — 处理用户打断</li><li><code>set_memory_from_history(conf_uid, history_uid)</code> — 从历史加载记忆</li></ul><h3 id="memoryagent" tabindex="-1">MemoryAgent <a class="header-anchor" href="#memoryagent" aria-label="Permalink to &quot;MemoryAgent&quot;">​</a></h3><p>当前唯一的 Agent 实现，职责是<strong>纯编排</strong>——自己不做拼接/解析，全部委托给子组件：</p><table tabindex="0"><thead><tr><th>组件</th><th>职责</th></tr></thead><tbody><tr><td><code>PromptBuilder</code></td><td>拼装 system prompt（base + vision summaries）</td></tr><tr><td><code>MessageFactory</code></td><td>构造 OpenAI 格式消息（支持多图、标签隔离）</td></tr><tr><td><code>MemoryStore</code></td><td>维护对话记忆 + 历史持久化</td></tr><tr><td><code>ToolRunner</code></td><td>运行 MCP tool loop，收集 trace 和回调图</td></tr><tr><td><code>VisionSummarizer</code></td><td>对图片生成文本摘要（快模式/细模式）</td></tr></tbody></table><h3 id="模式矩阵" tabindex="-1">模式矩阵 <a class="header-anchor" href="#模式矩阵" aria-label="Permalink to &quot;模式矩阵&quot;">​</a></h3><p>MemoryAgent 的行为由配置决定：</p><ul><li><strong>enable_tool</strong> — 是否先运行 MCP tool loop 再 chat</li><li><strong>chat_supports_vision</strong> — chat model 是否接受图片输入</li><li><strong>faster_first_response</strong> — 工具循环完成后是否加速首句响应</li><li><strong>segment_method</strong> — 断句方式（<code>pysbd</code> / 中文标点）</li><li><strong>interrupt_method</strong> — 中断信号注入方式（<code>system</code> / <code>user</code>）</li></ul><h3 id="输入-输出类型" tabindex="-1">输入 / 输出类型 <a class="header-anchor" href="#输入-输出类型" aria-label="Permalink to &quot;输入 / 输出类型&quot;">​</a></h3><p><strong>输入：</strong></p><ul><li><code>BatchInput</code> — 包含文本列表 + 可选图片 / 文件</li><li><code>ImageData</code> — 图片（camera / screen / clipboard / upload）</li><li><code>TextData</code> — 文本（input / clipboard），可带发送者名称</li></ul><p><strong>输出（流式 yield）：</strong></p><ul><li><code>SentenceOutput</code> — 一句话：display_text + tts_text + actions（表情/图片/音效）</li><li><code>AudioOutput</code> — 一段音频：audio_path + display_text + transcript + actions</li></ul><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><p>一次完整的对话请求经过以下处理管线：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📥 BatchInput（用户输入）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>🔧 [enable_tool?] ToolRunner</span></span>
<span class="line"><span>    → tool_trace + tool_images</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>👁️ [has_images?] VisionSummarizer</span></span>
<span class="line"><span>    → vision_summaries</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>📝 PromptBuilder</span></span>
<span class="line"><span>    → system_prompt (base + summaries)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>✉️ MessageFactory</span></span>
<span class="line"><span>    → OpenAI messages (prompt + text + images)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>🤖 AsyncLLM.chat_completion_stream</span></span>
<span class="line"><span>    → raw LLM response (streaming)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>🔄 Transformers 管线</span></span>
<span class="line"><span>    sentence_divider      # 断句</span></span>
<span class="line"><span>      → actions_extractor # 提取表情/音效</span></span>
<span class="line"><span>      → tts_filter        # TTS 文本清理</span></span>
<span class="line"><span>      → display_processor # 显示文本处理</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>📤 yield SentenceOutput</span></span>
<span class="line"><span>    (display_text, tts_text, actions)</span></span></code></pre></div><p><strong>关键节点：</strong></p><ul><li>🔧 工具调用是可选的（<code>enable_tool=True</code> 时触发）</li><li>👁️ 图片摘要根据模型能力决定（chat 不支持 vision 时必须生成）</li><li>🔄 Transformers 是纯文本后处理，不涉及 LLM 调用</li><li>📤 输出是流式的，逐句 yield</li></ul><h2 id="不变量" tabindex="-1">不变量 <a class="header-anchor" href="#不变量" aria-label="Permalink to &quot;不变量&quot;">​</a></h2><ul><li><strong>History 不写 base64</strong>：memory_store 只持久化纯文本内容</li><li><strong>Tool 图与用户图隔离</strong>：tool 回调图默认标签 <code>tool1</code>，与用户上传图语义分离</li></ul>`,26)])])}const m=s(p,[["render",l]]);export{h as __pageData,m as default};
